const days=['domingo','segunda','terça','quarta','quinta','sexta','sábado'];
const now=new Date(new Date().toLocaleString('en-US',{timeZone:'America/Sao_Paulo'}));
const pad=n=>String(n).padStart(2,'0');

const horaAtual=`${pad(now.getHours())}:${pad(now.getMinutes())}`;
const dataAtual=`${now.getFullYear()}-${pad(now.getMonth()+1)}-${pad(now.getDate())}`;

let r=`Agora são ${horaAtual} de ${days[now.getDay()]} ${pad(now.getDate())}/${pad(now.getMonth()+1)}/${String(now.getFullYear()).slice(2)}.\n`;
r+=`Timezone: America/Sao_Paulo (UTC-03:00)\n\n`;

for(let i=1;i<=6;i++){
  const f=new Date(now); f.setDate(now.getDate()+i);
  const iso=`${f.getFullYear()}-${pad(f.getMonth()+1)}-${pad(f.getDate())}`;
  if(i===1) r+=`Amanhã é ${days[f.getDay()]} ${pad(f.getDate())}/${pad(f.getMonth()+1)} → ${iso}\n`;
  else if(i===2) r+=`Depois de amanhã é ${days[f.getDay()]} ${pad(f.getDate())}/${pad(f.getMonth()+1)} → ${iso}\n`;
  else r+=`A próxima ${days[f.getDay()]} será dia ${pad(f.getDate())}/${pad(f.getMonth()+1)} → ${iso}\n`;
}
return [{json:{resultado:r.trim()}}];

// OPT-005: split deterministico (substitui agente LLM de split)
// Input: saida do no "Salvar Resposta Agente" com campo message_agent
// Output: { output: "<balao1>\n<balao2>\n..." } para o no "Separar Linhas Resposta"
const raw = ($input.first().json.message_agent || $input.first().json.output || '').toString();
// 1) strip markdown basico
let txt = raw
  .replace(/```[\s\S]*?```/g, m => m.replace(/```/g,''))
  .replace(/`([^`]*)`/g, '$1')
  .replace(/\*\*([^*]+)\*\*/g, '$1')
  .replace(/__([^_]+)__/g, '$1')
  .replace(/\*([^*]+)\*/g, '$1')
  .replace(/_([^_]+)_/g, '$1')
  .replace(/^#{1,6}\s+/gm, '')
  .replace(/\[([^\]]+)\]\([^)]+\)/g, '$1')
  .replace(/^\s*[-*+]\s+/gm, '')
  .replace(/^\s*\d+\.\s+/gm, '')
  .replace(/\r/g, '')
  .trim();
// 2) quebrar por paragrafo (\n\n) primeiro
const MAX = 700;
const paragraphs = txt.split(/\n{2,}/).map(p => p.trim()).filter(Boolean);
const baloes = [];
for (const p of paragraphs) {
  if (p.length <= MAX) { baloes.push(p); continue; }
  const sentences = p.split(/(?<=[.!?])\s+/);
  let buf = '';
  for (const s of sentences) {
    if ((buf + ' ' + s).trim().length > MAX && buf) { baloes.push(buf.trim()); buf = s; }
    else { buf = buf ? buf + ' ' + s : s; }
  }
  if (buf.trim()) baloes.push(buf.trim());
}
const output = baloes.join('\n');
return [{ json: { output } }];

